class Solution(object):
    def decodeCiphertext(self, encodedText, rows):
        cols = len(encodedText) // rows
        grid = [encodedText[i*cols:(i+1)*cols] for i in range(rows)]
        result = []
        for c in range(cols):
            for r in range(rows):
                if r + c < cols:
                    result.append(grid[r][c + r])
        return ''.join(result).rstrip()
